  .card {
    background: var(--bg-card); border: 1px solid var(--border);
    border-radius: 16px; padding: 32px;
  }
  .terminal {
    background: #0d1117; border: 1px solid #30363d; border-radius: 12px;
    padding: 24px; font-family: 'JetBrains Mono', monospace;
    font-size: 16px; line-height: 1.8; margin: 16px 0;
  }
  .terminal .prompt { color: var(--accent-green); }
  .terminal .cmd { color: var(--text-primary); }
  .terminal .output { color: var(--text-secondary); }
  .terminal .highlight-val { color: var(--accent-amber); }
  .terminal .comment { color: var(--text-muted); }

  .stat-box {
    background: var(--bg-card); border: 1px solid var(--border);
    border-radius: 16px; padding: 28px; text-align: center;
  }
  .insight-box {
    background: rgba(16, 185, 129, 0.08); border: 1px solid rgba(16, 185, 129, 0.25);
    border-radius: 16px; padding: 24px 28px; margin: 16px 0;
  }
  .insight-box p { font-size: 22px; font-weight: 500; color: var(--accent-green); line-height: 1.5; }

  /* Cover title at 68px per design system */
  .cover-title {
    font-size: 68px; font-weight: 800; line-height: 1.12;
