  }

  .slide-title {
    font-size: 58px; font-weight: 800; line-height: 1.15;
    margin-bottom: 24px; letter-spacing: -1px;
  }

  .slide-subtitle {
    font-size: 28px; font-weight: 500; line-height: 1.5;
    color: var(--text-secondary); margin-bottom: 32px;
  }

